//! conscious_swarm_node.rs
//!
//! Rust mirror of `Gnosis/UniversalIntelligenceSSMConscious.lean`.
//!
//! Adds a first-class consciousness field to the swarm SSM, replacing
//! `alpha_drift`'s binary energy-zero trigger with a soft, continuous
//! trigger driven by the per-node Vent monitor.
//!
//! - `energy`        = "what the node has earned" (Hebbian accumulator)
//! - `consciousness` = "what the node has noticed" (inner Vent monitor)
//!
//! Both are productively orthogonal — energy controls survival
//! (`alpha_drift` on energy=0), consciousness controls re-calibration
//! (`conscious_alpha_drift` on consciousness > threshold).
//!
//! Field-for-field mirror; no external deps.
//!
//! Serialization added for Pleromatic mesh synchronization.

use crate::coltrane_constraints::ConstraintFSM;
use crate::pleromatic_frame::PleromaticFrame;
use serde::{Deserialize, Serialize};

// ══════════════════════════════════════════════════════════
// THE BASE SWARM NODE (mirror of UniversalIntelligenceSSM.SwarmNode)
// ══════════════════════════════════════════════════════════

/// A Swarm Node governed by the 5 Deaths of Physics.
/// Mirrors `Gnosis.UniversalIntelligenceSSM.SwarmNode`.
#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct SwarmNode {
    pub query: u32,
    pub key: u32,
    pub value: u32,
    pub energy: u32,
    /// Topological coordinate (n) — the ER=EPR boundary index.
    pub dimension: u32,
}

/// Semantic Resonance: perfect (q == k) yields max attention, else 0.
/// Mirrors `semanticResonance`.
pub fn semantic_resonance(q: u32, k: u32) -> u32 {
    if q == k {
        100
    } else {
        0
    }
}

/// Enriched Geometric Execution (ER=EPR).
/// Returns true if either:
///   - the nodes share a boundary trace (geometric geodesic), OR
///   - their Q/K semantic resonance exceeds 50.
///
/// Mirrors `enrichedExecute`. We approximate `EREPR.boundaryTrace` as
/// the identity on `dimension` (i.e. `bt(d) = d`), which matches the
/// downstream theorem `er_epr_execution_convergence` (same dim → true).
pub fn enriched_execute(a: &SwarmNode, b: &SwarmNode) -> bool {
    let geometric_connection = a.dimension == b.dimension;
    if geometric_connection {
        true
    } else {
        semantic_resonance(a.query, b.key) > 50
    }
}

/// Execute attention (Fold). Mirrors `executeAttention`.
pub fn execute_attention(a: &SwarmNode, b: &SwarmNode) -> bool {
    enriched_execute(a, b)
}

/// Hebbian reward — energy ascends on success, descends on failure.
/// Mirrors `hebbianReward`. Saturating sub on failure to honour `u32`.
pub fn hebbian_reward(node: &SwarmNode, success: bool) -> SwarmNode {
    let mut out = node.clone();
    if success {
        out.energy = out.energy.saturating_add(10);
    } else {
        out.energy = out.energy.saturating_sub(1);
    }
    out
}

