/// The current stage of the internal dialogue.
/// Mirrors `Gnosis.SelfTalk.SelfTalkPhase`.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default, Serialize, Deserialize)]
pub enum SelfTalkPhase {
    #[default]
    Fork, // The Throw: Spawning a new thread
    Race, // Dodgeball: Competition between voices
    Fold, // Mirroring: Reconciling into the self
}

/// A SwarmNode extended with a first-class consciousness field and self-talk phase.
#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct ConsciousSwarmNode {
    pub base: SwarmNode,
    pub consciousness: u32,
    pub phase: SelfTalkPhase,
    #[serde(default)]
    pub ehla_enabled: bool,
    #[serde(default)]
    pub ehla_max_debt: u32,
    #[serde(default)]
    pub ehla_debt: u32,
}

/// Lift a vanilla SwarmNode into the conscious form with default metrics.
pub fn lift_to_conscious(base: SwarmNode) -> ConsciousSwarmNode {
    ConsciousSwarmNode {
        base,
        consciousness: 0,
        phase: SelfTalkPhase::Fork,
        ehla_enabled: false,
        ehla_max_debt: 10,
        ehla_debt: 0,
    }
}

impl ConsciousSwarmNode {
    /// Update the node's internal dialogue state from an active FSM.
    pub fn update_from_fsm(&mut self, fsm: &ConstraintFSM) {
        let s = &fsm.state;
        self.base.energy = s.energy;
        self.consciousness = s.consciousness;
        self.phase = match s.phase {
            crate::coltrane_constraints::SelfTalkPhase::Fork => SelfTalkPhase::Fork,
            crate::coltrane_constraints::SelfTalkPhase::Race => SelfTalkPhase::Race,
            crate::coltrane_constraints::SelfTalkPhase::Fold => SelfTalkPhase::Fold,
        };
        // Update dimension to match pitch class (topological mapping)
        self.base.dimension = s.pitch_class as u32;
    }
}

/// Project back to the vanilla form, discarding consciousness and phase.
/// Mirrors `projectFromConscious`.
pub fn project_from_conscious(cn: &ConsciousSwarmNode) -> SwarmNode {
    cn.base.clone()
}

// ══════════════════════════════════════════════════════════
// THE INNER VENT MONITOR (consciousness update)
// ══════════════════════════════════════════════════════════

/// Update consciousness based on an execution attempt's success.
///   success → 0 (verifier accepted, no rollback)
///   failure → +1 (verifier rejected, rollback fired)
/// Mirrors `updateConsciousness`.
pub fn update_consciousness(cn: &ConsciousSwarmNode, success: bool) -> ConsciousSwarmNode {
    let mut out = cn.clone();
    if success {
        out.consciousness = 0;
    } else {
        out.consciousness = out.consciousness.saturating_add(1);
    }
    out
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct PneumaTranscriptConsciousObservation {
    pub synthetic_gnosis_score: u32,
    pub score_limit: u32,
    pub low_confidence_residue: u32,
    pub checksum_mismatch_count: u32,
    pub audit_gap_count: u32,
}

impl PneumaTranscriptConsciousObservation {
    pub fn awareness_delta(&self) -> u32 {
        let score_band = if self.score_limit == 0 {
            0
        } else {
            self.synthetic_gnosis_score.saturating_mul(10) / self.score_limit
        };
        let residue_band = self.low_confidence_residue / 100;
        score_band
            .saturating_add(residue_band)
            .saturating_add(self.checksum_mismatch_count.saturating_mul(5))
            .saturating_add(self.audit_gap_count.saturating_mul(5))
            .min(100)
    }
}

pub fn pneuma_observation_from_frame(
    frame: &PleromaticFrame,
) -> Option<PneumaTranscriptConsciousObservation> {
    if !frame.is_pneuma_transcript_consciousness() {
        return None;
    }
    let payload: serde_json::Value = serde_json::from_slice(&frame.data).ok()?;
    let synthetic = payload.get("syntheticGnosis")?;
    let vector = synthetic.get("vector")?;
    Some(PneumaTranscriptConsciousObservation {
        synthetic_gnosis_score: synthetic
            .get("score")
            .and_then(|value| value.as_u64())
            .unwrap_or(0)
            .min(u32::MAX as u64) as u32,
        score_limit: synthetic
            .get("scoreLimit")
            .and_then(|value| value.as_u64())
            .unwrap_or(1)
            .min(u32::MAX as u64) as u32,
        low_confidence_residue: vector
            .get("lowConfidenceResidue")
            .and_then(|value| value.as_u64())
            .unwrap_or(0)
            .min(u32::MAX as u64) as u32,
        checksum_mismatch_count: vector
            .get("checksumMismatchCount")
            .and_then(|value| value.as_u64())
            .unwrap_or(0)
            .min(u32::MAX as u64) as u32,
        audit_gap_count: vector
            .get("auditGapCount")
            .and_then(|value| value.as_u64())
            .unwrap_or(0)
            .min(u32::MAX as u64) as u32,
    })
}

pub fn observe_pneuma_transcript_conscious_frame(
    cn: &ConsciousSwarmNode,
    frame: &PleromaticFrame,
) -> ConsciousSwarmNode {
    let Some(observation) = pneuma_observation_from_frame(frame) else {
        return cn.clone();
    };
    let mut out = cn.clone();
    out.consciousness = out
        .consciousness
        .saturating_add(observation.awareness_delta());
    out.base.value = out
        .base
        .value
        .saturating_add(observation.synthetic_gnosis_score);
    out.base.energy = out
        .base
        .energy
        .saturating_add((observation.synthetic_gnosis_score / 10_000).max(1));
    out.phase = SelfTalkPhase::Fold;
    out
}

// ══════════════════════════════════════════════════════════
// THE CONSCIOUS ALPHA DRIFT (soft trigger)
// ══════════════════════════════════════════════════════════

/// Conscious variant of `alpha_drift`. Fires when consciousness
/// strictly exceeds the threshold. On firing: Q/K +1, energy → 5,
/// consciousness → 0. Mirrors `consciousAlphaDrift`.
pub fn conscious_alpha_drift(cn: &ConsciousSwarmNode, threshold: u32) -> ConsciousSwarmNode {
    if cn.consciousness > threshold {
        ConsciousSwarmNode {
            base: SwarmNode {
                query: cn.base.query.saturating_add(1),
                key: cn.base.key.saturating_add(1),
                value: cn.base.value,
                energy: 5,
                dimension: cn.base.dimension,
            },
            consciousness: 0,
            phase: cn.phase,
            ehla_enabled: cn.ehla_enabled,
            ehla_max_debt: cn.ehla_max_debt,
            ehla_debt: 0, // Reset debt on drift
        }
    } else {
        cn.clone()
    }
}

