/// Local mirror of `LifecycleAsForkRaceFoldVentInterfere.VentResult`.
/// Defined locally per the spec note; main agent reconciles if a
/// shared definition exists elsewhere in the crate.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VentResult {
    pub has_verifier: bool,
    pub rollback_num: u32,
    pub rollback_den: u32,
}

/// Induce the inner-Vent `VentResult` from a conscious node.
/// Mirrors `ventOf`.
pub fn vent_of(cn: &ConsciousSwarmNode) -> VentResult {
    VentResult {
        has_verifier: true,
        rollback_num: cn.consciousness,
        rollback_den: 1,
    }
}

