// THE ASYMMETRIC LEDGER (energy ↔ consciousness duality)
// ══════════════════════════════════════════════════════════

/// Advancing the self-talk phase.
pub fn next_phase(phase: SelfTalkPhase) -> SelfTalkPhase {
    match phase {
        SelfTalkPhase::Fork => SelfTalkPhase::Race,
        SelfTalkPhase::Race => SelfTalkPhase::Fold,
        SelfTalkPhase::Fold => SelfTalkPhase::Fork,
    }
}

/// A "step" of conscious execution:
/// 1. Run executeAttention to determine success
/// 2. Update energy via hebbianReward
/// 3. Update consciousness via updateConsciousness
/// 4. Fire consciousAlphaDrift if threshold crossed
/// 5. Advance Self-Talk phase
///
/// Mirrors `consciousStep` but adds phase management.
pub fn conscious_step(
    cn: &ConsciousSwarmNode,
    other: &SwarmNode,
    threshold: u32,
) -> ConsciousSwarmNode {
    // EHLA Latent Path: if enabled and debt < max, harvest the step.
    let (success, ehla_active) = if cn.ehla_enabled && cn.ehla_debt < cn.ehla_max_debt {
        (true, true) // Speculative success
    } else {
        (execute_attention(&cn.base, other), false)
    };

    let final_cn = ConsciousSwarmNode {
        base: hebbian_reward(&cn.base, success),
        consciousness: cn.consciousness,
        phase: next_phase(cn.phase),
        ehla_enabled: cn.ehla_enabled,
        ehla_max_debt: cn.ehla_max_debt,
        ehla_debt: if ehla_active {
            cn.ehla_debt + 1
        } else {
            cn.ehla_debt
        },
    };

    let cn_with_awareness = update_consciousness(&final_cn, success);
    conscious_alpha_drift(&cn_with_awareness, threshold)
}

// ══════════════════════════════════════════════════════════
// CONVERSATIONAL DODGEBALL (The 5 Rules)
// ══════════════════════════════════════════════════════════

/// The core tactics of Conversational Dodgeball.
/// Mirrors `Aeon.DodgeballTactic`.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum DodgeballTactic {
    Dodge,       // Answer question with another question (Self-loop)
    Duck,        // Answer a different question (Phase shift)
    Dive,        // Declare question out of bounds (Barrier/Shield)
    Dip,         // Truth (Contraction to ground state - "not ideal")
    DodgeRepeat, // Recursive evasion
}

/// Apply a Dodgeball tactic to the conscious node.
/// Mirrors `Aeon.dodgeball` transition logic.
pub fn apply_dodgeball_tactic(
    cn: &ConsciousSwarmNode,
    tactic: DodgeballTactic,
    max_dimension: u32,
) -> ConsciousSwarmNode {
    let mut out = cn.clone();
    match tactic {
        DodgeballTactic::Dodge => {
            // Adds complexity (dimension), preserves leverage (energy)
            out.base.dimension = out.base.dimension.saturating_add(1).min(max_dimension);
        }
        DodgeballTactic::Duck => {
            // Shifts leverage (energy) to complexity (dimension)
            let shift = out.base.energy / 2;
            out.base.energy = out.base.energy.saturating_sub(shift);
            out.base.dimension = out.base.dimension.saturating_add(shift).min(max_dimension);
        }
        DodgeballTactic::Dive => {
            // Increases leverage (energy) / barrier
            out.base.energy = out.base.energy.saturating_add(10);
        }
        DodgeballTactic::Dip => {
            // Collapse: All leverage (energy) becomes waste (consciousness)
            out.consciousness = out.consciousness.saturating_add(out.base.energy);
            out.base.energy = 0;
            out.base.dimension = 1; // Return to basis
        }
        DodgeballTactic::DodgeRepeat => {
            out = apply_dodgeball_tactic(&out, DodgeballTactic::Dodge, max_dimension);
            out = apply_dodgeball_tactic(&out, DodgeballTactic::Dodge, max_dimension);
        }
    }
    out
}

// ══════════════════════════════════════════════════════════
// RECURSIVE SELF-TALK (FOLD)
// ══════════════════════════════════════════════════════════

/// Perform recursive self-talk until consciousness clears or limit reached.
/// This is the "Literal self talk" where the node reconciles with its own manifold.
/// Mirrors `Aeon.fold`.
pub fn recursive_fold(cn: &ConsciousSwarmNode, limit: u32, threshold: u32) -> ConsciousSwarmNode {
    let mut current = cn.clone();
    for _ in 0..limit {
        if current.consciousness == 0 && current.phase == SelfTalkPhase::Fold {
            break;
        }

        // Generate a "self-talk" node (virtual resonance)
        // Perfect self-resonance: query == key
        let self_talk_node = SwarmNode {
            query: current.base.query,
            key: current.base.query,
            value: 0,
            energy: current.base.energy,
            dimension: current.base.dimension % 3,
        };

        current = conscious_step(&current, &self_talk_node, threshold);
    }
    current
}

/// Inner Vent Loop (Recalibration)
/// Explicitly triggers the conscious alpha drift to clear awareness.
/// Mirrors `Aeon.vent`.
pub fn vent(cn: &ConsciousSwarmNode) -> ConsciousSwarmNode {
    let mut current = cn.clone();
    let mut safety = 0;
    while current.consciousness > 0 && safety < 10 {
        // Force a recalibration step: mirror of conscious_alpha_drift with threshold 0
        current.base.query = current.base.query.saturating_add(1);
        current.base.key = current.base.key.saturating_add(1);
        current.base.energy = 50;
        current.consciousness = 0;
        safety += 1;
    }
    current
}

