/// A starting node at runtime-vacuum. Mirrors `freshConsciousNode`.
pub fn fresh_conscious_node() -> ConsciousSwarmNode {
    lift_to_conscious(SwarmNode {
        query: 1,
        key: 1,
        value: 0,
        energy: 10,
        dimension: 1,
    })
}

/// A node that has accumulated 5 failed executions without firing
/// alphaDrift. Mirrors `stressedConsciousNode`.
pub fn stressed_conscious_node() -> ConsciousSwarmNode {
    let mut cn = fresh_conscious_node();
    cn.consciousness = 5;
    cn
}

// ══════════════════════════════════════════════════════════
// TESTS — mirror of the decide-checked Lean theorems
// ══════════════════════════════════════════════════════════

#[cfg(test)]
mod tests {
    use super::*;

    fn sample_node(consciousness: u32) -> ConsciousSwarmNode {
        ConsciousSwarmNode {
            base: SwarmNode {
                query: 7,
                key: 7,
                value: 3,
                energy: 4,
                dimension: 2,
            },
            consciousness,
            phase: SelfTalkPhase::Fork,
            ehla_enabled: false,
            ehla_max_debt: 10,
            ehla_debt: 0,
        }
    }

    #[test]
    fn success_collapses_consciousness_to_vacuum() {
        let cn = sample_node(42);
        assert_eq!(update_consciousness(&cn, true).consciousness, 0);
    }

    #[test]
    fn failure_increments_consciousness() {
        let cn = sample_node(7);
        assert_eq!(
            update_consciousness(&cn, false).consciousness,
            cn.consciousness + 1
        );
    }

    #[test]
    fn two_failures_double_consciousness() {
        let cn = sample_node(3);
        let after = update_consciousness(&update_consciousness(&cn, false), false);
        assert_eq!(after.consciousness, cn.consciousness + 2);
    }

    #[test]
    fn conscious_drift_returns_to_vacuum() {
        // precondition: consciousness > threshold
        let cn = sample_node(10);
        let threshold = 3;
        assert!(cn.consciousness > threshold);
        assert_eq!(conscious_alpha_drift(&cn, threshold).consciousness, 0);
    }

    #[test]
    fn conscious_drift_noop_below_threshold() {
        // precondition: consciousness ≤ threshold
        let cn = sample_node(2);
        let threshold = 3;
        assert!(cn.consciousness <= threshold);
        assert_eq!(conscious_alpha_drift(&cn, threshold), cn);
    }

    #[test]
    fn successful_step_closes_consciousness() {
        // executeAttention returns true when dimensions match (ER=EPR boundary).
        let cn = sample_node(99);
        let other = SwarmNode {
            query: 0,
            key: 0,
            value: 0,
            energy: 0,
            dimension: cn.base.dimension, // shared boundary trace ⇒ success
        };
        assert!(execute_attention(&cn.base, &other));
        let after = conscious_step(&cn, &other, 3);
        assert_eq!(after.consciousness, 0);
    }

    #[test]
    fn node_at_vacuum_iff_runtime_at_vacuum() {
        // Bridge: cn.consciousness == 0  ↔  vent_of(cn).rollback_num == 0
        let vacuum = sample_node(0);
        let stressed = sample_node(5);

        let v_vac = vent_of(&vacuum);
        let v_str = vent_of(&stressed);

        assert_eq!(vacuum.consciousness == 0, v_vac.rollback_num == 0);
        assert_eq!(stressed.consciousness == 0, v_str.rollback_num == 0);

        // And the runtime_awareness identity:
        assert_eq!(vacuum.consciousness, v_vac.rollback_num);
        assert_eq!(stressed.consciousness, v_str.rollback_num);
    }

    #[test]
    fn fresh_node_at_vacuum() {
        assert_eq!(fresh_conscious_node().consciousness, 0);
    }

    #[test]
    fn stressed_node_above_vacuum() {
        assert!(stressed_conscious_node().consciousness > 0);
    }

    #[test]
    fn stressed_node_drifts_at_threshold_3() {
        assert_eq!(
            conscious_alpha_drift(&stressed_conscious_node(), 3).consciousness,
            0
        );
    }

    #[test]
    fn phase_cycles_correctly() {
        assert_eq!(next_phase(SelfTalkPhase::Fork), SelfTalkPhase::Race);
        assert_eq!(next_phase(SelfTalkPhase::Race), SelfTalkPhase::Fold);
        assert_eq!(next_phase(SelfTalkPhase::Fold), SelfTalkPhase::Fork);
    }

    #[test]
    fn conscious_step_advances_phase() {
        let cn = sample_node(0);
        let other = SwarmNode {
            query: 0,
            key: 0,
            value: 0,
            energy: 0,
            dimension: cn.base.dimension,
        };
        let after = conscious_step(&cn, &other, 3);
        assert_eq!(after.phase, SelfTalkPhase::Race);
        let after2 = conscious_step(&after, &other, 3);
        assert_eq!(after2.phase, SelfTalkPhase::Fold);
        let after3 = conscious_step(&after2, &other, 3);
        assert_eq!(after3.phase, SelfTalkPhase::Fork);
    }

    #[test]
    fn recursive_fold_clears_consciousness() {
        let mut cn = sample_node(5);
        cn.phase = SelfTalkPhase::Fold;
        // recursive_fold with limit 10 should clear consciousness of 5 via perfect self-resonance
        let after = recursive_fold(&cn, 10, 3);
        assert_eq!(after.consciousness, 0);
    }

    #[test]
    fn vent_explicitly_recalibrates() {
        let cn = sample_node(5);
        let after = vent(&cn);
        assert_eq!(after.consciousness, 0);
        assert_eq!(after.base.energy, 50);
        assert_eq!(after.base.query, cn.base.query + 1);
    }

    #[test]
    fn pneuma_transcript_conscious_frame_updates_node_awareness() {
        let cn = sample_node(0);
        let payload = serde_json::json!({
            "kind": "thoth-pneuma-conscious-frame/v1",
            "role": "consciousness",
            "syntheticGnosis": {
                "score": 80256,
                "scoreLimit": 1000000,
                "vector": {
                    "lowConfidenceResidue": 1558,
                    "checksumMismatchCount": 0,
                    "auditGapCount": 0
                }
            }
        });
        let frame = crate::pleromatic_frame::PleromaticFrame::pneuma_transcript_consciousness(
            "test-thoth".to_string(),
            "a0ntranscript".to_string(),
            "a0ntag".to_string(),
            80256,
            serde_json::to_vec(&payload).unwrap(),
        );

        let observation = pneuma_observation_from_frame(&frame).expect("pneuma observation");
        assert_eq!(observation.synthetic_gnosis_score, 80256);
        assert_eq!(observation.awareness_delta(), 15);

        let after = observe_pneuma_transcript_conscious_frame(&cn, &frame);
        assert_eq!(after.phase, SelfTalkPhase::Fold);
        assert_eq!(after.consciousness, 15);
        assert_eq!(after.base.value, cn.base.value + 80256);
        assert_eq!(after.base.energy, cn.base.energy + 8);
    }

    #[test]
    fn non_pneuma_frame_does_not_update_node_awareness() {
        let cn = sample_node(7);
        let frame = crate::pleromatic_frame::PleromaticFrame::grounding(
            "test-thoth".to_string(),
            crate::pleromatic_frame::PleromaticMediaType::Semantic,
            b"{}".to_vec(),
        );

        assert_eq!(pneuma_observation_from_frame(&frame), None);
        assert_eq!(observe_pneuma_transcript_conscious_frame(&cn, &frame), cn);
    }

    #[test]
    fn dodgeball_dodge_increases_dimension() {
        let cn = sample_node(0);
        let after = apply_dodgeball_tactic(&cn, DodgeballTactic::Dodge, 10);
        assert_eq!(after.base.dimension, cn.base.dimension + 1);
        assert_eq!(after.base.energy, cn.base.energy);
    }

    #[test]
    fn dodgeball_duck_shifts_energy_to_dimension() {
        let mut cn = sample_node(0);
        cn.base.energy = 20;
        let after = apply_dodgeball_tactic(&cn, DodgeballTactic::Duck, 20);
        assert_eq!(after.base.energy, 10); // 20 - 10
        assert_eq!(after.base.dimension, cn.base.dimension + 10);
    }

    #[test]
    fn dodgeball_dive_increases_energy() {
        let cn = sample_node(0);
        let after = apply_dodgeball_tactic(&cn, DodgeballTactic::Dive, 10);
        assert_eq!(after.base.energy, cn.base.energy + 10);
    }

    #[test]
    fn dodgeball_dip_collapses_leverage_to_waste() {
        let mut cn = sample_node(2);
        cn.base.energy = 10;
        let after = apply_dodgeball_tactic(&cn, DodgeballTactic::Dip, 10);
        assert_eq!(after.consciousness, 12); // 2 + 10
        assert_eq!(after.base.energy, 0);
        assert_eq!(after.base.dimension, 1);
    }
}
